INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-appraiser-moex-00373', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '《荀子．解蔽》：「夏首之南有人焉，曰涓蜀梁。其為人也，愚而善畏。明月而宵行，俯見其影，以為 伏鬼也。卬視其髮，以為立魅也。背而走，比至其家，失氣而死」，如果用成語來描寫本寓言所形容的 心理狀態，下列選項那一個最不合適？', '["杯弓蛇影", "風聲鶴唳", "疑心暗鬼", "燭影斧聲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00374', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '請仔細閱讀、品賞文氣與思理後，將下列各段文句重組，排成一個合理而流暢的長句：①今學者曠廢隳', '["雖百工技藝，未有不本於志者", "志不立，天下無可成之事", "而百無所成，皆由於 志之未立耳", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00375', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '下列詠史之作，與「楚 漢相爭」人物無關的是：', '["八尺將軍千里騅，拔山扛鼎不妨奇。范增力盡無施處，路到烏江君自知", "不握兵權只坐籌，苦辭萬戶乞討留。縱令不早尋仙去，天子終無賜醢謀", "久與君王共苦辛，功成身退步逡巡。五湖渺渺煙波闊，誰是扁舟第二人", "鳥盡良弓勢必藏，千秋青史費評章。區區一飯猶圖報，爭肯為臣負漢王"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00376', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '凡要說的有三個以上的事物，這些事物又有大小輕重等比例，於是說話行文時，依序層層遞推，這種修 辭方法叫做「層遞」。下列文句屬於「層遞」的是：', '["將軍百戰死，壯士十年歸，歸來見天子，天子坐明堂", "知者不惑，仁者不憂，勇者不懼", "先父族，次母族，次妻族，而後及其疏遠之賢", "夫天地者，萬物之逆旅也；光陰者，百代之過客也 ⑤五霸莫盛於桓、文，文公之才，不過桓公，其臣又皆不及仲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00377', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '下列語文常識中，說明正確的是：', '["六書中以「形聲字」最多，如「江」、「射」、「問」皆屬形聲字", "「金文」是流行於商、周時期，鑄刻於青銅器上的文字，也稱鐘鼎文字", "「馬拉松」、「宅急便」、「水噹噹」、「瑜珈」都是時下流行的外來語", "「零落」、「參差」、「躊躇」、「落寞」都是雙聲的聯綿詞"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00378', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '下列四首詩，各詠贊一位佳人，請依四位佳人所處時代之先後，排出正確順序：', '["飄飄秀色奪仙春，只恐丹青畫不真。能為君主罷征戍，甘心玉骨葬胡塵", "華清恩幸古無倫，猶恐蛾眉不勝人。未免被他褒女笑，只叫天子暫蒙塵", "長揖雄談態自殊，美人巨眼識窮途，屍居餘氣楊公幕，豈得羈縻女丈夫", "遺恨江東應未消，芳魂零亂任西飄，八千子弟同歸漢，不負君恩是楚腰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00379', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '張潮《幽夢影》：「梅邊之石宜古，松下之石宜拙，竹旁之石宜   ，盆內之石宜   」，上引文句中應 填入的字，最恰當的選項是：', '["巧／瘦", "小／峭", "瘦／巧", "小／巧"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00380', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '①三吏三別之後／兩鬢已蒼／也該寫點雲淡風輕的自己了／躑躇浣花溪頭／忽然水一般靜了下來', '["風靜了，我是／默默的雪。他在／敗葦間穿行，好落寞的／神色，這人一朝是／東京八十萬禁軍教頭／ 如今行船悄悄向梁山落草／山是憂戚的樣子", "我打此經過／寫了幾首詩／和女子調笑／他們戲稱我為／帝王／歷史要數說我／亡國的罪愆／但是／ 我的罪／何止亡國", "詩史寫到建安就得爬一座大山／歌雖然短／但沒酒不行／朝露被逐呎的海拔逐呎驅散／聽覺裡全是呦 呦的鹿鳴 以上新詩所指涉的對象依序是：", "杜甫／宋江／劉義慶／劉伶"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00381', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '文中晏子不死君難，主要是因為他認為：', '["大臣身負國家重任，不可輕易言死", "莊公不應私通棠姜，贊成崔子弒君", "保留有用之身，才可以伺機為國君報仇", "國君不是因社稷而亡，大臣沒有必要殉死"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00382', 'real-estate-appraiser', 'real-estate-appraiser-moex-100-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '文中「臣君者，豈為其口實」，意謂為人臣子：', '["不是為了拿俸祿來供養自己", "不可落人口實，受人非議", "怎麼可以做出弒君這種天理不容的事情呢", "可以找藉口推卸責任嗎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "7cdb41681d05", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL)
